import os
from datetime import datetime, timedelta

import jwt
from flask import Flask, jsonify, request

app = Flask(__name__)

# --- Configuration ---
# Use a strong, randomly generated secret key in a real application.
# For simplicity, we are using a hardcoded one here.
# os.urandom(24).hex() can generate a good key
app.config['SECRET_KEY'] = os.environ.get('SECRET_KEY', 'super-secret-key-for-dev')
app.config['JWT_ALGORITHM'] = 'HS256'
app.config['JWT_EXPIRATION_DELTA_MINUTES'] = 30  # Token valid for 30 minutes

# --- User Data (In a real app, this would be a database) ---
users_db = {
    'alice': {'password': 'password123', 'roles': ['user']},
    'bob': {'password': 'securepwd', 'roles': ['admin', 'user']},
}


# --- JWT Helper Functions ---
def generate_token(user_id, roles):
    """Generates a JWT token for the given user_id and roles."""
    payload = {
        'user_id': user_id,
        'roles': roles,
        'exp': datetime.utcnow() + timedelta(minutes=app.config['JWT_EXPIRATION_DELTA_MINUTES'])
    }
    return jwt.encode(payload, app.config['SECRET_KEY'], algorithm=app.config['JWT_ALGORITHM'])


def decode_token(token):
    """Decodes a JWT token and returns its payload, or None if invalid/expired."""
    try:
        return jwt.decode(token, app.config['SECRET_KEY'], algorithms=[app.config['JWT_ALGORITHM']])
    except jwt.ExpiredSignatureError:
        return {'error': 'Token has expired'}
    except jwt.InvalidTokenError:
        return {'error': 'Invalid token'}


# --- Decorators for Authentication and Authorization ---
def jwt_required(f):
    """Decorator to protect routes requiring a valid JWT token."""
    def wrapper(*args, **kwargs):
        token = None
        if 'Authorization' in request.headers:
            try:
                token = request.headers['Authorization'].split(' ')[1]
            except IndexError:
                return jsonify({'message': 'Invalid Authorization header format'}), 401
        
        if not token:
            return jsonify({'message': 'Token is missing!'}), 401

        current_user_payload = decode_token(token)

        if 'error' in current_user_payload:
            return jsonify({'message': current_user_payload['error']}), 401

        request.current_user = current_user_payload['user_id']
        request.current_user_roles = current_user_payload['roles']

        return f(*args, **kwargs)
    wrapper.__name__ = f.__name__ # Needed for Flask to register unique endpoints
    return wrapper


def roles_required(roles):
    """Decorator to protect routes based on user roles."""
    def decorator(f):
        @jwt_required
        def wrapper(*args, **kwargs):
            if not any(role in request.current_user_roles for role in roles):
                return jsonify({'message': 'Permission denied: Insufficient roles'}), 403
            return f(*args, **kwargs)
        wrapper.__name__ = f.__name__
        return wrapper
    return decorator


# --- API Endpoints ---

@app.route('/')
def home():
    return jsonify({'message': 'Welcome to the Flask JWT Auth API!'})


@app.route('/login', methods=['POST'])
def login():
    """Authenticates user and issues a JWT token."""
    auth_data = request.get_json()
    username = auth_data.get('username')
    password = auth_data.get('password')

    if not username or not password:
        return jsonify({'message': 'Username and password are required'}), 400

    user_info = users_db.get(username)

    if user_info and user_info['password'] == password:
        token = generate_token(username, user_info['roles'])
        return jsonify({'token': token}), 200
    else:
        return jsonify({'message': 'Invalid credentials'}), 401


@app.route('/protected', methods=['GET'])
@jwt_required
def protected_route():
    """An example of a route that requires a valid JWT token."""
    return jsonify({
        'message': f'Hello {request.current_user}! You accessed a protected route.',
        'your_roles': request.current_user_roles
    })


@app.route('/admin-only', methods=['GET'])
@roles_required(['admin'])
def admin_only_route():
    """An example of a route that requires 'admin' role."""
    return jsonify({
        'message': f'Hello Admin {request.current_user}! You have access to admin content.',
        'your_roles': request.current_user_roles
    })


@app.route('/user-or-admin', methods=['GET'])
@roles_required(['user', 'admin'])
def user_or_admin_route():
    """An example of a route that requires 'user' or 'admin' role."""
    return jsonify({
        'message': f'Hello {request.current_user}! You have access because you are a user or admin.',
        'your_roles': request.current_user_roles
    })


if __name__ == '__main__':
    app.run(debug=True) # Set debug=False in production